package com.example.bankapp.domain;

import java.util.Locale;
import java.util.regex.Pattern;

public final class InputValidators {
    private static final Pattern ACCOUNT_ID = Pattern.compile("^[A-Z0-9\\-]{4,32}$");
    private static final Pattern CURRENCY = Pattern.compile("^\\d{1,12}(\\.\\d{1,2})?$");

    private InputValidators() {}

    public static String normalizeAccountId(String raw) {
        if (raw == null) return null;
        return raw.trim().toUpperCase(Locale.US);
    }

    public static boolean isValidAccountId(String raw) {
        String v = normalizeAccountId(raw);
        return v != null && ACCOUNT_ID.matcher(v).matches();
    }

    public static boolean isValidAmountString(String raw) {
        if (raw == null) return false;
        String v = raw.trim();
        return CURRENCY.matcher(v).matches();
    }
}

package com.example.bankapp.domain;

import java.math.BigDecimal;
import java.math.RoundingMode;

public final class Money {
    private Money() {}

    public static long dollarsToCents(BigDecimal amount) {
        if (amount == null) throw new IllegalArgumentException("amount==null");
        BigDecimal scaled = amount.setScale(2, RoundingMode.HALF_UP);
        return scaled.movePointRight(2).longValueExact();
    }

    public static BigDecimal centsToDollars(long cents) {
        return new BigDecimal(cents).movePointLeft(2);
    }

    public static String formatUsd(long cents) {
        BigDecimal d = centsToDollars(cents);
        return "$" + d.setScale(2, RoundingMode.HALF_UP).toPlainString();
    }
}

