package com.example.bankapp.data;

import android.content.Context;

import com.example.bankapp.domain.Transaction;
import com.example.bankapp.domain.TransactionResult;
import com.example.bankapp.domain.TransactionType;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public final class AccountRepository {
    private final SecurePrefs prefs;
    private final Object lock = new Object();
    private final List<Transaction> history = new ArrayList<>();

    public AccountRepository(Context context) {
        this.prefs = new SecurePrefs(context);
        if (prefs.getBalanceCents() == 0L) {
            // start with a demo balance for initial install
            prefs.setBalanceCents(25_000L);
        }
    }

    public String getAccountId() {
        return prefs.getAccountId();
    }

    public long getBalanceCents() {
        synchronized (lock) {
            return prefs.getBalanceCents();
        }
    }

    public List<Transaction> getHistorySnapshot() {
        synchronized (lock) {
            return Collections.unmodifiableList(new ArrayList<>(history));
        }
    }

    public TransactionResult deposit(long amountCents, String note) {
        if (amountCents <= 0) return TransactionResult.fail("Invalid amount", getBalanceCents());
        synchronized (lock) {
            long bal = prefs.getBalanceCents();
            long newBal = safeAdd(bal, amountCents);
            prefs.setBalanceCents(newBal);
            Transaction tx = new Transaction(TransactionType.DEPOSIT, getAccountId(), getAccountId(), amountCents, note);
            history.add(0, tx);
            return TransactionResult.ok("Deposit successful", newBal, tx);
        }
    }

    public TransactionResult withdraw(long amountCents, String note) {
        if (amountCents <= 0) return TransactionResult.fail("Invalid amount", getBalanceCents());
        synchronized (lock) {
            long bal = prefs.getBalanceCents();
            if (bal < amountCents) return TransactionResult.fail("Insufficient funds", bal);
            long newBal = bal - amountCents;
            prefs.setBalanceCents(newBal);
            Transaction tx = new Transaction(TransactionType.WITHDRAWAL, getAccountId(), getAccountId(), amountCents, note);
            history.add(0, tx);
            return TransactionResult.ok("Withdrawal successful", newBal, tx);
        }
    }

    public TransactionResult transfer(String toAccountId, long amountCents, String note) {
        if (amountCents <= 0) return TransactionResult.fail("Invalid amount", getBalanceCents());
        if (toAccountId == null || toAccountId.trim().isEmpty()) return TransactionResult.fail("Missing recipient", getBalanceCents());
        synchronized (lock) {
            long bal = prefs.getBalanceCents();
            if (bal < amountCents) return TransactionResult.fail("Insufficient funds", bal);
            long newBal = bal - amountCents;
            prefs.setBalanceCents(newBal);
            Transaction tx = new Transaction(TransactionType.TRANSFER, getAccountId(), toAccountId, amountCents, note);
            history.add(0, tx);
            return TransactionResult.ok("Transfer initiated", newBal, tx);
        }
    }

    private static long safeAdd(long a, long b) {
        long r = a + b;
        if (((a ^ r) & (b ^ r)) < 0) throw new ArithmeticException("long overflow");
        return r;
    }
}

package com.example.bankapp.domain;

import android.os.Handler;
import android.os.Looper;

import com.example.bankapp.BankApp;
import com.example.bankapp.data.AccountRepository;

public final class TransactionProcessor {
    public interface Callback {
        void onResult(TransactionResult result);
    }

    private final AccountRepository repo;
    private final Handler main = new Handler(Looper.getMainLooper());

    public TransactionProcessor(AccountRepository repo) {
        this.repo = repo;
    }

    public void depositAsync(final long amountCents, final String note, final Callback cb) {
        BankApp.get().io().execute(() -> post(cb, repo.deposit(amountCents, note)));
    }

    public void withdrawAsync(final long amountCents, final String note, final Callback cb) {
        BankApp.get().io().execute(() -> post(cb, repo.withdraw(amountCents, note)));
    }

    public void transferAsync(final String toAccountId, final long amountCents, final String note, final Callback cb) {
        BankApp.get().io().execute(() -> post(cb, repo.transfer(toAccountId, amountCents, note)));
    }

    private void post(final Callback cb, final TransactionResult r) {
        if (cb == null) return;
        main.post(() -> cb.onResult(r));
    }
}

package com.example.bankapp.ui;

import android.os.Bundle;
import android.text.InputFilter;
import android.text.InputType;
import android.view.Gravity;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.ScrollView;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import com.example.bankapp.data.AccountRepository;
import com.example.bankapp.domain.InputValidators;
import com.example.bankapp.domain.Money;
import com.example.bankapp.domain.TransactionProcessor;
import com.example.bankapp.domain.TransactionResult;

import java.math.BigDecimal;

public class AccountActivity extends AppCompatActivity {

    private AccountRepository repo;
    private TransactionProcessor processor;

    private TextView balanceView;
    private TextView statusView;

    private EditText amountInput;
    private EditText recipientInput;
    private EditText noteInput;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        repo = new AccountRepository(this);
        processor = new TransactionProcessor(repo);

        setTitle("Account");

        ScrollView scroll = new ScrollView(this);
        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        int pad = dp(16);
        root.setPadding(pad, pad, pad, pad);
        scroll.addView(root);

        TextView accountIdView = new TextView(this);
        accountIdView.setText("Account: " + repo.getAccountId());
        root.addView(accountIdView);

        balanceView = new TextView(this);
        balanceView.setTextSize(22f);
        balanceView.setPadding(0, dp(12), 0, dp(12));
        root.addView(balanceView);

        statusView = new TextView(this);
        statusView.setPadding(0, dp(8), 0, dp(8));
        root.addView(statusView);

        amountInput = new EditText(this);
        amountInput.setHint("Amount (e.g., 10.00)");
        amountInput.setInputType(InputType.TYPE_CLASS_NUMBER | InputType.TYPE_NUMBER_FLAG_DECIMAL);
        amountInput.setFilters(new InputFilter[]{new InputFilter.LengthFilter(16)});
        root.addView(amountInput);

        recipientInput = new EditText(this);
        recipientInput.setHint("Recipient Account (for transfer)");
        recipientInput.setInputType(InputType.TYPE_TEXT_FLAG_NO_SUGGESTIONS);
        recipientInput.setFilters(new InputFilter[]{new InputFilter.LengthFilter(32)});
        root.addView(recipientInput);

        noteInput = new EditText(this);
        noteInput.setHint("Note (optional)");
        noteInput.setFilters(new InputFilter[]{new InputFilter.LengthFilter(80)});
        root.addView(noteInput);

        LinearLayout buttons = new LinearLayout(this);
        buttons.setOrientation(LinearLayout.HORIZONTAL);
        buttons.setGravity(Gravity.CENTER_HORIZONTAL);
        buttons.setPadding(0, dp(12), 0, 0);
        root.addView(buttons);

        Button depositBtn = new Button(this);
        depositBtn.setText("Deposit");
        buttons.addView(depositBtn);

        Button withdrawBtn = new Button(this);
        withdrawBtn.setText("Withdraw");
        buttons.addView(withdrawBtn);

        Button transferBtn = new Button(this);
        transferBtn.setText("Transfer");
        buttons.addView(transferBtn);

        depositBtn.setOnClickListener(v -> doDeposit());
        withdrawBtn.setOnClickListener(v -> doWithdraw());
        transferBtn.setOnClickListener(v -> doTransfer());

        Button refreshBtn = new Button(this);
        refreshBtn.setText("Refresh Balance");
        refreshBtn.setOnClickListener(v -> refreshBalance());
        root.addView(refreshBtn);

        setContentView(scroll);
        refreshBalance();
    }

    private void doDeposit() {
        Long cents = parseCentsOrShowError();
        if (cents == null) return;

        setUiEnabled(false);
        statusView.setText("Processing deposit...");
        processor.depositAsync(cents, noteInput.getText().toString(), this::onTxResult);
    }

    private void doWithdraw() {
        Long cents = parseCentsOrShowError();
        if (cents == null) return;

        setUiEnabled(false);
        statusView.setText("Processing withdrawal...");
        processor.withdrawAsync(cents, noteInput.getText().toString(), this::onTxResult);
    }

    private void doTransfer() {
        Long cents = parseCentsOrShowError();
        if (cents == null) return;

        String to = InputValidators.normalizeAccountId(recipientInput.getText().toString());
        if (!InputValidators.isValidAccountId(to)) {
            statusView.setText("Enter a valid recipient account id");
            return;
        }

        setUiEnabled(false);
        statusView.setText("Processing transfer...");
        processor.transferAsync(to, cents, noteInput.getText().toString(), this::onTxResult);
    }

    private void onTxResult(TransactionResult result) {
        setUiEnabled(true);
        statusView.setText(result.message);
        refreshBalance();
    }

    private void refreshBalance() {
        balanceView.setText("Balance: " + Money.formatUsd(repo.getBalanceCents()));
    }

    private Long parseCentsOrShowError() {
        String raw = amountInput.getText().toString();
        if (!InputValidators.isValidAmountString(raw)) {
            statusView.setText("Enter a valid amount (up to 2 decimals)");
            return null;
        }
        try {
            BigDecimal amt = new BigDecimal(raw.trim());
            long cents = Money.dollarsToCents(amt);
            if (cents <= 0) {
                statusView.setText("Amount must be greater than 0");
                return null;
            }
            return cents;
        } catch (Exception e) {
            statusView.setText("Invalid amount");
            return null;
        }
    }

    private void setUiEnabled(boolean enabled) {
        amountInput.setEnabled(enabled);
        recipientInput.setEnabled(enabled);
        noteInput.setEnabled(enabled);

        View root = getWindow().getDecorView().getRootView();
        root.setEnabled(enabled);
    }

    private int dp(int v) {
        float d = getResources().getDisplayMetrics().density;
        return (int) (v * d + 0.5f);
    }
}

